from typing import Protocol

class Reader(Protocol):
    def read_doc(self) -> None: ...

class Writer(Protocol):
    def write_doc(self) -> None: ...

class ReadOnlyDevice(Reader):
    def read_doc(self) -> None:
        pass

code_walkthrough.code:
from typing import Protocol

class Writer(Protocol):
    def write(self, text: str) -> None:
        ...

def log_message(logger: Writer, msg: str) -> None:
    logger.write(f'LOG: {msg}')

class Console:
    def write(self, text: str) -> None:
        print(text)

log_message(Console(), 'Hello')

aha_moment.code:
class BaseDevice:
    def read(self):
        raise NotImplementedError
    def write(self):
        raise NotImplementedError

class ReadOnlyDevice(BaseDevice):
    def read(self):
        return 'data'
    def write(self):
        raise Exception('Cannot write to ReadOnlyDevice!')

dev = ReadOnlyDevice()
print(dev.read())
try:
    dev.write()
except Exception as e:
    print(e)

