from typing import Protocol

class Worker(Protocol):
    def work(self) -> None:
        ...

class Eater(Protocol):
    def eat(self) -> None:
        ...

class Human:
    def work(self) -> None:
        print('Human working')
    def eat(self) -> None:
        print('Human eating')

class Robot:
    def work(self) -> None:
        print('Robot working')
